// src/components/AllocationEngine.js
import React, { useState } from "react";
import { DISASTER_ZONES, RESOURCES } from "../data/mockData";
import "./AllocationEngine.css";

const TYPE_COLOR = { medical: "#EF4444", rescue: "#F59E0B", food: "#10B981", shelter: "#3B82F6" };

function computePriorityScore(zone) {
  const severityWeight = { critical: 1.0, high: 0.75, medium: 0.5, low: 0.25 };
  const needAvg = (zone.needs.medical + zone.needs.rescue + zone.needs.food + zone.needs.shelter) / 4;
  const affectedRatio = zone.affectedCount / zone.population;
  const sev = severityWeight[zone.severity];
  const score = Math.round((needAvg * 0.4 + affectedRatio * 100 * 0.3 + sev * 100 * 0.3));
  return Math.min(100, score);
}

function generateRecommendations(zones, resources) {
  const standby = resources.filter((r) => r.status === "standby");
  const sorted = [...zones].sort((a, b) => computePriorityScore(b) - computePriorityScore(a));
  const recs = [];

  sorted.forEach((zone) => {
    const score = computePriorityScore(zone);
    if (zone.needs.medical > 70) {
      const med = standby.find((r) => r.type === "medical");
      if (med) {
        recs.push({
          id: `rec-${zone.id}-medical`,
          resource: med,
          zone,
          reason: `Medical need at ${zone.needs.medical}% — critical threshold exceeded`,
          urgency: zone.needs.medical >= 90 ? "immediate" : "high",
          score,
          type: "medical",
        });
      }
    }
    if (zone.needs.food > 65) {
      const food = standby.find((r) => r.type === "food");
      if (food) {
        recs.push({
          id: `rec-${zone.id}-food`,
          resource: food,
          zone,
          reason: `Food/water supply at ${zone.needs.food}% — ${zone.affectedCount.toLocaleString()} people at risk`,
          urgency: "high",
          score,
          type: "food",
        });
      }
    }
  });

  return recs;
}

export default function AllocationEngine() {
  const [running, setRunning] = useState(false);
  const [done, setDone] = useState(false);
  const [applied, setApplied] = useState([]);
  const [manualZone, setManualZone] = useState("");
  const [manualResource, setManualResource] = useState("");
  const [manualAllocations, setManualAllocations] = useState([]);

  const recommendations = generateRecommendations(DISASTER_ZONES, RESOURCES);
  const standbyResources = RESOURCES.filter((r) => r.status === "standby");

  const handleRunAI = () => {
    setRunning(true);
    setDone(false);
    setTimeout(() => {
      setRunning(false);
      setDone(true);
    }, 2200);
  };

  const applyRec = (rec) => {
    setApplied((prev) => [...prev, rec.id]);
  };

  const handleManualAllocate = () => {
    if (!manualZone || !manualResource) return;
    const zone = DISASTER_ZONES.find((z) => z.id === manualZone);
    const res  = RESOURCES.find((r) => r.id === manualResource);
    if (!zone || !res) return;
    setManualAllocations((prev) => [...prev, { zone, resource: res, id: `manual-${Date.now()}` }]);
    setManualZone("");
    setManualResource("");
  };

  return (
    <div className="page">
      <div className="page-header">
        <h1>AI Allocation Engine</h1>
        <p>Intelligent resource-to-zone matching using real-time need scoring and priority algorithms</p>
      </div>

      <div className="alloc-layout">
        {/* Left — AI engine */}
        <div>
          {/* Engine card */}
          <div className="card engine-card">
            <div className="engine-header">
              <div>
                <div className="card-title">Smart Allocation Engine</div>
                <div style={{ fontSize: 13, color: "var(--slate)" }}>
                  Analyzes zone needs, population, severity, and resource availability
                </div>
              </div>
              <div className="ai-badge">
                <span className="ai-spark">✦</span> AI
              </div>
            </div>

            <div className="algo-factors">
              <div className="algo-factor">
                <div className="af-icon" style={{ color: "#EF4444" }}>◉</div>
                <div>
                  <div className="af-name">Severity Weight</div>
                  <div className="af-desc">Critical zones get 4× priority multiplier</div>
                </div>
                <div className="af-pct" style={{ color: "#EF4444" }}>40%</div>
              </div>
              <div className="algo-factor">
                <div className="af-icon" style={{ color: "#F59E0B" }}>◉</div>
                <div>
                  <div className="af-name">Need Index</div>
                  <div className="af-desc">Averaged across medical, food, rescue, shelter</div>
                </div>
                <div className="af-pct" style={{ color: "#F59E0B" }}>35%</div>
              </div>
              <div className="algo-factor">
                <div className="af-icon" style={{ color: "#3B82F6" }}>◉</div>
                <div>
                  <div className="af-name">Population Impact</div>
                  <div className="af-desc">Affected persons as ratio of total population</div>
                </div>
                <div className="af-pct" style={{ color: "#3B82F6" }}>25%</div>
              </div>
            </div>

            <button
              className={`btn btn-primary engine-run-btn ${running ? "running" : ""}`}
              onClick={handleRunAI}
              disabled={running}
            >
              {running ? (
                <>
                  <span className="spinner" />
                  Analyzing Zones...
                </>
              ) : done ? (
                <>✓ Re-run Analysis</>
              ) : (
                <>✦ Run AI Analysis</>
              )}
            </button>
          </div>

          {/* Zone priority table */}
          <div className="card" style={{ marginTop: 16 }}>
            <div className="card-title">Zone Priority Scores</div>
            <div className="priority-list">
              {[...DISASTER_ZONES]
                .sort((a, b) => computePriorityScore(b) - computePriorityScore(a))
                .map((zone, idx) => {
                  const score = computePriorityScore(zone);
                  return (
                    <div key={zone.id} className="priority-row">
                      <div className="priority-rank">{idx + 1}</div>
                      <div className="priority-info">
                        <div className="priority-name">{zone.name.split("—")[0].trim()}</div>
                        <div className="priority-type">{zone.type} · {zone.affectedCount.toLocaleString()} affected</div>
                      </div>
                      <div className="priority-score-wrap">
                        <div
                          className="priority-score-bar"
                          style={{
                            width: `${score}%`,
                            background: score >= 70 ? "#EF4444" : score >= 50 ? "#F59E0B" : "#3B82F6",
                          }}
                        />
                        <span className="priority-score-num">{score}</span>
                      </div>
                      <span className={`badge badge-${zone.severity}`}>{zone.severity}</span>
                    </div>
                  );
                })}
            </div>
          </div>
        </div>

        {/* Right — Recommendations + Manual */}
        <div>
          {/* AI Recommendations */}
          <div className="card" style={{ marginBottom: 16 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
              <div className="card-title" style={{ marginBottom: 0 }}>AI Recommendations</div>
              {done && <span className="badge badge-high">{recommendations.length} actions</span>}
            </div>

            {!done ? (
              <div className="empty-state">
                {running ? (
                  <div className="analyzing">
                    <div className="analyze-spinner" />
                    <div>Analyzing {DISASTER_ZONES.length} zones and {RESOURCES.length} resources...</div>
                    <div style={{ fontSize: 11, color: "var(--slate-dim)", marginTop: 4 }}>Computing optimal allocation matrix</div>
                  </div>
                ) : (
                  <div style={{ color: "var(--slate)", fontSize: 13 }}>
                    Run the AI Analysis to get resource allocation recommendations.
                  </div>
                )}
              </div>
            ) : (
              <div className="recs-list">
                {recommendations.map((rec) => {
                  const isApplied = applied.includes(rec.id);
                  return (
                    <div key={rec.id} className={`rec-card ${isApplied ? "rec-applied" : ""}`}>
                      <div className="rec-header">
                        <div className="rec-type-dot" style={{ background: TYPE_COLOR[rec.type] }} />
                        <div className="rec-title">{rec.resource.name}</div>
                        <span className={`badge badge-${rec.urgency === "immediate" ? "critical" : "high"}`}>
                          {rec.urgency}
                        </span>
                      </div>
                      <div className="rec-arrow">
                        <div className="rec-from">{rec.resource.location}</div>
                        <div className="rec-arrow-line">→</div>
                        <div className="rec-to">{rec.zone.name.split("—")[0].trim()}</div>
                      </div>
                      <div className="rec-reason">{rec.reason}</div>
                      <div className="rec-footer">
                        <div style={{ fontSize: 11, color: "var(--slate)" }}>
                          Priority Score: <strong style={{ color: "var(--white)" }}>{rec.score}</strong>
                        </div>
                        {isApplied ? (
                          <span className="badge badge-deployed">✓ Applied</span>
                        ) : (
                          <button className="btn btn-primary btn-sm" onClick={() => applyRec(rec)}>
                            Apply
                          </button>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          {/* Manual allocation */}
          <div className="card">
            <div className="card-title">Manual Override</div>
            <div style={{ fontSize: 12, color: "var(--slate)", marginBottom: 12 }}>
              Manually assign a standby resource to a zone
            </div>
            <div className="manual-form">
              <select
                className="alloc-select"
                value={manualResource}
                onChange={(e) => setManualResource(e.target.value)}
              >
                <option value="">Select resource...</option>
                {standbyResources.map((r) => (
                  <option key={r.id} value={r.id}>{r.name}</option>
                ))}
              </select>
              <select
                className="alloc-select"
                value={manualZone}
                onChange={(e) => setManualZone(e.target.value)}
              >
                <option value="">Select zone...</option>
                {DISASTER_ZONES.map((z) => (
                  <option key={z.id} value={z.id}>{z.name.split("—")[0].trim()}</option>
                ))}
              </select>
              <button
                className="btn btn-primary"
                onClick={handleManualAllocate}
                disabled={!manualZone || !manualResource}
              >
                Allocate
              </button>
            </div>

            {manualAllocations.length > 0 && (
              <div style={{ marginTop: 14 }}>
                <div className="card-title" style={{ marginBottom: 8 }}>Manual Allocations</div>
                {manualAllocations.map((ma) => (
                  <div key={ma.id} className="manual-alloc-row">
                    <span className="badge badge-standby">Manual</span>
                    <span style={{ fontSize: 12 }}>{ma.resource.name}</span>
                    <span style={{ color: "var(--slate)", fontSize: 12 }}>→</span>
                    <span style={{ fontSize: 12 }}>{ma.zone.name.split("—")[0].trim()}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
